head.script:
scwin.strCurrDate = $c.date.getServerDateTime(); // 현재 날짜 반환

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    udc_rsltsStdDt.setInitDate(scwin.strCurrDate, scwin.strCurrDate);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    ed_homeClntNo.setValue("");				//거래처번호
    ed_homeClntNm.setValue("");			//거래처명

    ed_clntNo.setValue("");
    ed_clntNm.setValue("");

    ed_vehclNoCd.setValue("");
    ed_vehclNo.setValue("");

    udc_rsltsStdDt.setInitDate(scwin.strCurrDate, scwin.strCurrDate);

};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    if (dma_condition.get("rsltsStdDtSt") == "" || dma_condition.get("rsltsStdDtEnd") == "") {
        $c.win.alert("실적기간은 필수 입력 항목입니다.");
        return false;
    }

    if (!$c.gus.cfIsAfterDate(ed_rsltsStdDtSt.getValue(), ed_rsltsStdDtEnd.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    //tr_retrieve.post();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        totalRows.setValue(ds_results.getRowCount());

        if (ds_results.getRowCount() == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
        else {
            gr_results.setFocusedCell(0, 0);
        }
    }
};

scwin.udc_homeClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNo, ed_homeClntNm, 1);
};

scwin.udc_homeClntNo_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_homeClntNm, ed_homeClntNo, 1, false);
};


scwin.udc_homeClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_homeClntNo.getValue(), ed_homeClntNm.getValue(), 'F', 'F');
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, ed_clntNm, 2);
};

scwin.udc_clntNo_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_clntNo, 2, false);
};

scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_clntNo.getValue(), ed_clntNm.getValue(), 'F', 'F');
};

scwin.udc_vehclNoCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNoCd, ed_vehclNo, 3);
};

scwin.udc_vehclNoCd_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_vehclNoCd, 3, false);
};

scwin.udc_vehclNoCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_vehclNoCd.getValue(), ed_vehclNo.getValue(), 'F', 'T');
};

//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, row) {

    pCode = pCode.trim();

    switch (disGubun) {
        //거래처
        case 1:
            var condition = "";
            if (cbx_cnd_chb_repClntYn.getValue() == 1) {
                condition = "RP";
            }
            udc_homeClntNo.setSelectId('retrieveSubsidaryClntListJa');
            udc_homeClntNo.cfCommonPopUp(scwin.udc_homeClntNo_callBackFunc	    // XML상의 SELECT ID
                , pCode							// 화면에서의 ??? Code Element의	Value
                , pName							// 화면에서의 ??? Name Element의	Value
                , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - ndefault (2)
                , null							// Title순서
                , '150,170'  		    		// 보여주는 각 컬럼들의 폭
                , null							// 컬럼중에서 숨기는	컬럼 지정
                , condition						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null							// 윈도우 위치 Y좌표
                , null							// 윈도우 위치 X좌표
                , null							// 중복체크여부	("F")
                , pAllSearch						// 전체검색허용여부	("F")
                , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 2:
            var condition = "";
            if (cbx_cnd_chb_repClntYn.getValue() == 1) {
                condition = "RP";
            }
            udc_clntNo.setSelectId('retrieveSubsidaryClntListJa');
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc	    // XML상의 SELECT ID
                , pCode							// 화면에서의 ??? Code Element의	Value
                , pName							// 화면에서의 ??? Name Element의	Value
                , pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - ndefault (2)
                , null							// Title순서
                , '150,170'  		    		// 보여주는 각 컬럼들의 폭
                , null							// 컬럼중에서 숨기는	컬럼 지정
                , condition						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null							// 윈도우 위치 Y좌표
                , null							// 윈도우 위치 X좌표
                , null							// 중복체크여부	("F")
                , pAllSearch						// 전체검색허용여부	("F")
                , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        //차량번호
