                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null							// 윈도우 위치 Y좌표	
                , null							// 윈도우 위치 X좌표
                , null							// 중복체크여부	("F")
                , 'T'							// 전체검색허용여부	("F")
                , "차량번호,차량단축코드,차량번호"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 5: // 소속거래처 (그리드)
            udc_gridComm.setSelectId('retrieveSubsidaryClntListJa');	    // XML상의 SELECT ID
            await udc_gridComm.cfCommonPopUp(
                function (rtnList) {
