                , 'T'							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null							// Title순서
                , '150,170'  		    		// 보여주는 각 컬럼들의 폭
                , null							// 컬럼중에서 숨기는	컬럼 지정
                , null							// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null							// 윈도우 위치 Y좌표
                , null							// 윈도우 위치 X좌표
                , null							// 중복체크여부	("F")
                , 'T'							// 전체검색허용여부	("F")
                , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 6: // 매니저 (그리드)
            udc_gridComm.setSelectId("retrieveSubsidaryClntListJa"); // XML상의 SELECT ID
            await udc_gridComm.cfCommonPopUp(
                function (rtnList) {
                    scwin.udc_gridClnt_callBackFunc(rtnList, row); // 추가 값 전달
                }
                , pCode							// 화면에서의 ??? Code Element의	Value
                , pName							// 화면에서의 ??? Name Element의	Value
                , 'T'							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null							// Title순서
                , '150,170'  		    		// 보여주는 각 컬럼들의 폭
                , null							// 컬럼중에서 숨기는	컬럼 지정
                , null							// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null							// 윈도우 위치 Y좌표
                , null							// 윈도우 위치 X좌표
                , null							// 중복체크여부	("F")
                , 'T'							// 전체검색허용여부	("F")
                , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 7: // 매출입 항목 (그리드)
            udc_gridComm.setSelectId('retrieveSelpchItemInfo');		// XML상의 SELECT ID
            udc_gridComm.cfCommonPopUp(
                function (rtnList) {
                    scwin.udc_gridClnt_callBackFunc(rtnList, row);
                }
                , pCode							// 화면에서의 ??? Code Element의	Value
                , pName							// 화면에서의 ??? Name Element의	Value
                , 'T'							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null							// Title순서	
                , null							// 보여주는 각 컬럼들의 폭	
                , null							// 컬럼중에서 숨기는	컬럼 지정	
                , ',,,,,'						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null							// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null							// 윈도우 위치 Y좌표	
                , null							// 윈도우 위치 X좌표
                , null                   		// 중복체크여부
                , null                   		// 전체검색허용여부
                , null                   		// POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  							
            );
            break;


        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

scwin.udc_homeClntNo_callBackFunc = function (rtnList) {
    if (rtnList != null) {
        //cfSetReturnValue(rtnList, ed_homeClntNo, ed_homeClntNm);
        ed_homeClntNo.setValue(rtnList[0]);
        ed_homeClntNm.setValue(rtnList[1]);
        dma_condition.set("upperClntNo", rtnList[5]);
    }
};

scwin.udc_clntNo_callBackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ed_clntNo.setValue(rtnList[0]);
        ed_clntNm.setValue(rtnList[1]);
    }
};

scwin.udc_vehclNoCd_callBackFunc = function (rtnList) {
    if (rtnList != null) {
        //cfSetReturnValue(rtnList, ed_vehclNoCd, ed_vehclNo);
        ed_vehclNoCd.setValue(rtnList[0]);
        ed_vehclNo.setValue(rtnList[1]);
        ed_homeClntNo.setValue(rtnList[3]);
        ed_homeClntNm.setValue(rtnList[4]);
    }
};

// 그리드 차량번호 callback
scwin.udc_gridVehcl_callBackFunc = function (rtnList, rowIndex) {
    if (rtnList != null) {
        ds_results.setCellData(rowIndex, "vehclNo", rtnList[1]);
        ds_results.setCellData(rowIndex, "homeClntNo", rtnList[3]);
        ds_results.setCellData(rowIndex, "homeClntNm", rtnList[4]);
        ds_results.setCellData(rowIndex, "clntNo", rtnList[5]);
        ds_results.setCellData(rowIndex, "clntNm", rtnList[6]);
        ds_results.setCellData(rowIndex, "eqCd", rtnList[7]);

        gr_results.setFocusedCell(rowIndex, "rsltsStdDt", true);
    }
}
// 그리드 매니저 callback
scwin.udc_gridClnt_callBackFunc = function (rtnList, rowIndex) {
    if (rtnList != null) {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "clntNo", "clntNm");
    }
};

// 그리드 소속거래처 callback
scwin.udc_gridHomeClnt_callBackFunc = function (rtnList, row) {
    if (rtnList != null) {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "homeClntNo", "homeClntNm");
    }
}

// 그리드 매출입항목목 callback
scwin.udc_gridClnt_callBackFunc = function (rtnList, row) {
    if (rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "selpchItemCd", "selpchItemNm");

        if (rtnList[2] === 0) {
            ds_results.setCellData(row, "taxnClsCd", "03");
            ds_results.setCellData(row, "clntVat", 0);
        } else {
            ds_results.setCellData(row, "taxnClsCd", "01");
        }
    }
}

// drmFileSubmit명 고정 - ASIS 사용안함
scwin.drmFileSubmit = function () {
}


//-------------------------------------------------------------------------
// function name : f_Upload
// function desc : 엑셀업로드
// CSV 업로드 버튼
//-------------------------------------------------------------------------
scwin.btn_upload_csv_onclick = async function () {
    let options = {
        startRowIndex: 1
    };

    ds_330_FillUse.removeAll();
    if (lc_uploadExt.getValue() == "1") {
        await $c.data.uploadGridViewCSV(gr_330_FillUse, options); // CSV 파일 업로드
    } else {
        await $c.data.uploadGridViewExcel(gr_330_FillUse, options);
    }
};

// 업로드 완료 이벤트
scwin.gr_330_FillUse_onfilereadend = function () {
    scwin.f_Upload();
};

// ds_330_FillUse → ds_results 복사 + 검증
scwin.f_Upload = function () {
    ds_results.removeAll();
    let altMsg = "";
    let totalCnt = ds_330_FillUse.getRowCount();

    for (let i = 0; i < totalCnt; i++) {
        if (!ds_330_FillUse.getCellData(i, "rsltsStdDt")) continue;

        let nRow = ds_results.insertRow();
        ds_results.setCellData(nRow, "rsltsStdDt", ds_330_FillUse.getCellData(i, "rsltsStdDt"));
        ds_results.setCellData(nRow, "vehclNo", ds_330_FillUse.getCellData(i, "vehclNo"));
        ds_results.setCellData(nRow, "homeClntNo", ds_330_FillUse.getCellData(i, "homeClntNo"));
        ds_results.setCellData(nRow, "clntNo", ds_330_FillUse.getCellData(i, "clntNo"));
        ds_results.setCellData(nRow, "clntNm", ds_330_FillUse.getCellData(i, "clntNm"));
        ds_results.setCellData(nRow, "amt01", ds_330_FillUse.getCellData(i, "amt01"));
        ds_results.setCellData(nRow, "amt02", ds_330_FillUse.getCellData(i, "amt02"));
        ds_results.setCellData(nRow, "amt03", ds_330_FillUse.getCellData(i, "amt03"));
        ds_results.setCellData(nRow, "amt04", ds_330_FillUse.getCellData(i, "amt04"));
        ds_results.setCellData(nRow, "amt05", ds_330_FillUse.getCellData(i, "amt05"));
        ds_results.setCellData(nRow, "amt06", ds_330_FillUse.getCellData(i, "amt06"));
        ds_results.setCellData(nRow, "amt07", ds_330_FillUse.getCellData(i, "amt07"));
        ds_results.setCellData(nRow, "amt08", ds_330_FillUse.getCellData(i, "amt08"));
        ds_results.setCellData(nRow, "amt09", ds_330_FillUse.getCellData(i, "amt09"));
        ds_results.setCellData(nRow, "amt10", ds_330_FillUse.getCellData(i, "amt10"));
        ds_results.setCellData(nRow, "amt11", ds_330_FillUse.getCellData(i, "amt11"));
        ds_results.setCellData(nRow, "amt12", ds_330_FillUse.getCellData(i, "amt12"));
        ds_results.setCellData(nRow, "amt13", ds_330_FillUse.getCellData(i, "amt13"));
        ds_results.setCellData(nRow, "amt14", ds_330_FillUse.getCellData(i, "amt14"));
        ds_results.setCellData(nRow, "amt15", ds_330_FillUse.getCellData(i, "amt15"));
        ds_results.setCellData(nRow, "amt16", ds_330_FillUse.getCellData(i, "amt16"));
        ds_results.setCellData(nRow, "amt17", ds_330_FillUse.getCellData(i, "amt17"));
        ds_results.setCellData(nRow, "amt18", ds_330_FillUse.getCellData(i, "amt18"));
        ds_results.setCellData(nRow, "amt19", ds_330_FillUse.getCellData(i, "amt19"));
        ds_results.setCellData(nRow, "etc01", ds_330_FillUse.getCellData(i, "etc01"));
        ds_results.setCellData(nRow, "etc02", ds_330_FillUse.getCellData(i, "etc02"));
        ds_results.setCellData(nRow, "etc03", ds_330_FillUse.getCellData(i, "etc03"));
        ds_results.setCellData(nRow, "etc04", ds_330_FillUse.getCellData(i, "etc04"));
        ds_results.setCellData(nRow, "etc05", ds_330_FillUse.getCellData(i, "etc05"));
        ds_results.setCellData(nRow, "etc06", ds_330_FillUse.getCellData(i, "etc06"));
        ds_results.setCellData(nRow, "etc07", ds_330_FillUse.getCellData(i, "etc07"));
        ds_results.setCellData(nRow, "etc08", ds_330_FillUse.getCellData(i, "etc08"));
        ds_results.setCellData(nRow, "etc09", ds_330_FillUse.getCellData(i, "etc09"));
        ds_results.setCellData(nRow, "etc10", ds_330_FillUse.getCellData(i, "etc10"));
        ds_results.setCellData(nRow, "etc11", ds_330_FillUse.getCellData(i, "etc11"));
        ds_results.setCellData(nRow, "etc12", ds_330_FillUse.getCellData(i, "etc12"));
        ds_results.setCellData(nRow, "etc13", ds_330_FillUse.getCellData(i, "etc13"));
        ds_results.setCellData(nRow, "etc14", ds_330_FillUse.getCellData(i, "etc14"));
        ds_results.setCellData(nRow, "etc15", ds_330_FillUse.getCellData(i, "etc15"));
        ds_results.setCellData(nRow, "etc16", ds_330_FillUse.getCellData(i, "etc16"));
        ds_results.setCellData(nRow, "etc17", ds_330_FillUse.getCellData(i, "etc17"));

        // amt10 vs etc01~17 합산 검증
        let amt10 = Number(ds_330_FillUse.getCellData(i, "amt10")) || 0;
        let etcSum = 0;
        for (let n = 1; n <= 17; n++) {
            etcSum += Number(ds_330_FillUse.getCellData(i, "etc" + String(n).padStart(2, "0"))) || 0;
        }
        if (amt10 != etcSum) {
            if (altMsg !== "") altMsg += ", ";
            altMsg += (nRow + 1);
        }
    }

    ds_330_FillUse.removeAll();

    if (altMsg !== "") {
        $c.win.alert(altMsg + "행의 기타매출액과 기타매출상세의 합이 일치하지 않습니다.");
    }

    totalRows.setValue(ds_results.getRowCount());
};

