//-------------------------------------------------------------------------
// function name : f_Apply
// function desc : 적용 
//-------------------------------------------------------------------------
scwin.btn_apply_onclick = async function (e) {
    let checkedCnt = 0;

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        //INSERT
        if (ds_results.getRowStatusValue(i) == "1") { //Gaus -> 3:update / WebSquare -> 1: 갱신
            if (ds_results.getCellData(i, "uploadNo") == "") {
                $c.win.alert("업로드 후 적용해주세요");
                return;
            }
            if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
                $c.win.alert("적용된 데이터는 재 적용할 수 없습니다.");
                return;
            }
            checkedCnt++;
        }
    }//for

    if (checkedCnt == 0) {
        $c.win.alert("적용 할 데이터가 없습니다.");
        return false;
    }

    let confirm = await $c.win.confirm("업로드 한 운송임을 등록하시겠습니까?");
    if (confirm) {
        //tr_apply.Post();
        $c.sbm.execute(sbm_apply);
    }
};

scwin.sbm_apply_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_002); // 성공적으로 등록하였습니다.
        scwin.btn_retrieve_onclick();
    }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    let checkedCnt = 0;

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        //INSERT
        if (ds_results.getRowStatusValue(i) == "2") { // 신규 생성
            //if(!cfValidateValue(ds_results.getCellData(i, "rsltsStdDt"), "date=YYYYMMDD")) {
            if (!$c.date.isDate(ds_results.getCellData(i, "rsltsStdDt"))) {
                $c.gus.cfAlertMsg((i + 1) + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
                return;
            }
            if (ds_results.getCellData(i, "rsltsStdDt") == "") {
                $c.win.alert((i + 1) + "행의 실적일자는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "vehclNo") == "") {
                $c.win.alert((i + 1) + "행의 차량번호는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "homeClntNo") == "") {
                $c.win.alert((i + 1) + "행의 소속거래처는 필수 입력 항목 입니다.");
                return false;
            }
            if (ds_results.getCellData(i, "clntNo") == "" && ds_results.getCellData(i, "clntNm") == "") {
                $c.win.alert((i + 1) + "행의 매니저코드/명  중 하나는 필수 입력 항목 입니다.");
                return false;
            }

            checkedCnt++;
        }
        //DELETE
        if (ds_results.getRowStatusValue(i) == "3") { // 삭제
            checkedCnt++;
        }
    }//for

    if (checkedCnt == 0) {
        $c.win.alert("저장 할 데이터가 없습니다.");
        return false;
    }

    let confirm = await $c.win.confirm(MSG_CM_CRM_001); //저장하시겠습니까?
    if (confirm) {
        //tr_save.Post();
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.btn_retrieve_onclick();
    }
};

//-------------------------------------------------------------------------
// 행삭제
//------------------------------------------------------------------------- 
scwin.btn_delete_onclick = async function (e) {
    // 실적관리번호 체크// 2026-03-30[T-5935] 체크된 행만 삭제 검증 가능하도록 개선
    let checkedCount = 0;
    for (let i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "chk") != "1") continue;
        checkedCount++;
        if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
            $c.win.alert("적용 후 실적번호가 생성된경우 삭제할 수 없습니다.");
            return;
        }
    }
    if (checkedCount === 0) {
        $c.win.alert("삭제할 데이터가 없습니다.");
        return;
    }

    let confirm = await $c.win.confirm(MSG_CM_CRM_004);
    if (!confirm) return;

    // 역방향 루프로 deleteRow (순방향은 index 밀림)
    for (let i = ds_results.getRowCount() - 1; i >= 0; i--) {
        if (ds_results.getCellData(i, "chk") == "1") {
            ds_results.deleteRow(i);
        }
    }

    $c.sbm.execute(sbm_delete);
};

scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004); // 성공적으로 삭제하였습니다
        scwin.btn_retrieve_onclick();
    }
};
